9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	type Item = {
23	  type: string;
24	  material?: string;
25	  enchantment?: number;
26	  cursed?: boolean;
27	};
28	type QuoteStep = { op: "quote"; items: Item[] };
29	type Customer = { yearsWithMHPCO: number };
30	type Scenario = { customer: Customer; steps: QuoteStep[] };
31	type QuoteResult = { premium: number };
32	type ScenarioResult = { results: QuoteResult[] };
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	const isKnownType = (item: Item): boolean =>
37	  item.type in BASE_PREMIUMS || COMPONENT_TYPES.has(item.type);
38	
39	const validateItems = (items: Item[]): void => {
40	  for (const item of items) {
41	    if (!isKnownType(item)) {
42	      throw new Error(`Unknown item type: ${item.type}`);
43	    }
44	  }
45	};
46	
47	const countByType = (items: Item[]): Map<string, number> => {
48	  const counts = new Map<string, number>();
49	  for (const item of items) {
50	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
51	  }
52	  return counts;
53	};
54	
55	const componentTypeBase = (count: number): number =>
56	  count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;
57	
58	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
59	
60	const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
61	
62	const mainItemSurcharge = (item: Item): number => {
63	  const base = mainItemBase(item);
64	  const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
65	  const highEnch =
66	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
67	  return cursed + highEnch;
68	};
69	
70	const mainItemsBase = (items: Item[]): number =>
71	  sum(items.filter((item) => !isComponent(item)).map(mainItemBase));
72	
73	const componentsBase = (items: Item[]): number => {
74	  const counts = countByType(items.filter(isComponent));
75	  return sum([...counts.values()].map(componentTypeBase));
76	};
77	
78	const itemSurcharges = (items: Item[]): number => sum(items.map(mainItemSurcharge));
79	
80	const policyBase = (items: Item[]): number => mainItemsBase(items) + componentsBase(items);
81	
82	const loyaltyDiscount = (base: number, customer: Customer): number =>
83	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;
