90	  const loyalty = loyaltyDiscount(base, customer);
91	  const followUp = isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
92	  return {
93	    premium: Math.ceil(base + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE),
94	  };
95	};
